void s_FillPCReaddatapacket(int saddr,int len)
{
	printf("s_FillPCReaddatapacket %d\n",len);

	//u8 F6datapacket[264];
	u8 *buf=(u8 *)malloc(len+8);
	u16 index=0;
	buf[index++]=gHJXHAPInfo.rightleftflag;
	buf[index++]=0x03;
	buf[index++]=len>>24;
	buf[index++]=(len>>16)&0xff;
	buf[index++]=(len>>8)&0xff;
	buf[index++]=(len>>0)&0xff;
	//s_HJXReadHAP(&buf[index],saddr,eaddr-saddr);
	s_HJXRead70132K(&buf[index],saddr,len);
	index+=len;
	GetCrC(buf,index,&buf[index]);
	printf_buf(buf, len+8);
	s_HJXBleSend(buf,len+8);
	free(buf);

}
void s_FillPCUpdatedatapacket()
{
	printf("s_FillPCUpdatedatapacket\n");
	u8 buf[9];
	u16 index=0,appcs=0;
	buf[index++]=gHJXHAPInfo.rightleftflag;
	buf[index++]=0x06;
	GetCrC(gHJXBleData.buf,gHJXBleData.len-2,&appcs);
	printf("appcs:%x\n",appcs);
	if(appcs==(gHJXBleData.buf[gHJXBleData.len-2]|(gHJXBleData.buf[gHJXBleData.len-1]<<8)))
	{
		printf("ok!");
		memcpy(&gHJXEEPPointer[(gHJXBleData.buf[2]<<24)|(gHJXBleData.buf[3]<<16)|(gHJXBleData.buf[4]<<8)|(gHJXBleData.buf[5]<<0)],&gHJXBleData.buf[6],1);
		//s_HJXWrite70132K(gHJXEEPPointer,0,EEP_SIZE);
	}


	buf[index++]=gHJXBleData.buf[2];
	buf[index++]=gHJXBleData.buf[3];
	buf[index++]=gHJXBleData.buf[4];
	buf[index++]=gHJXBleData.buf[5];

	buf[index++]=gHJXBleData.buf[6];
	GetCrC(buf,sizeof(buf)-2,&buf[index]);
	printf_buf(buf,sizeof(buf));
	s_HJXBleSend(buf,sizeof(buf));
}
void s_FillPCTrancedatapacket()
{
	printf("s_FillPCTrancedatapacket\n");
	u8 buf[5];
	u16 index=0,appcs=0;
	buf[index++]=gHJXHAPInfo.rightleftflag;
	buf[index++]=0x10;
	GetCrC(gHJXBleData.buf,gHJXBleData.len-2,&appcs);
	printf("appcs:%x\n",appcs);
	if(appcs==(gHJXBleData.buf[gHJXBleData.len-2]|(gHJXBleData.buf[gHJXBleData.len-1]<<8)))
	{
