    },
    children: [

      // ===== 标题 =====
      new Paragraph({ heading: HeadingLevel.HEADING_1, alignment: AlignmentType.CENTER,
        children: [new TextRun({ text: "JL700N 蓝牙助听器 BLE 通讯协议", bold: true, size: 48, font: "Arial" })] }),
      new Paragraph({ alignment: AlignmentType.CENTER, spacing: { after: 200 },
        children: [new TextRun({ text: "版本 V1.0  |  2026-04-20", size: 20, color: "666666", font: "Arial" })] }),

      new Paragraph({ heading: HeadingLevel.HEADING_2, children: [new TextRun("1. 概述")] }),
      new Paragraph({ spacing: { after: 120 },
        children: [new TextRun({ text: "本文档详细描述 JL700N 蓝牙助听器在 BLE 验配模式下与 PC / APP 的通讯协议。", size: 20, font: "Arial" })] }),

