          ]}),
          new TableRow({ children: [
            hexCell("0x06", 1200), cell("C_PC_DATA_UPDATE", 2400), cell("PC→设备", 1800), cell("单字节更新 EEPROM", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0x10", 1200), cell("C_PC_DATA_TRANCE", 2400), cell("PC→设备", 1800), cell("批量写入 EEPROM（烧录）", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0x04", 1200), cell("C_PC_DATA_RESET", 2400), cell("PC→设备", 1800), cell("复位 HAP，写入 Flash", 3960)
          ]}),
        ]
      }),

      new Paragraph({ heading: HeadingLevel.HEADING_2, children: [new TextRun("5.2 APP 协议汇总")] }),
      new Table({
        columnWidths: [1200, 2400, 1800, 3960],
        rows: [
          new TableRow({ children: [
            hcell("CMD", 1200), hcell("名称", 2400), hcell("方向", 1800), hcell("用途", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0xA0", 1200), cell("C_HJX_BLE_READ", 2400), cell("APP→设备", 1800), cell("读取完整设备信息（67字节）", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0xA2", 1200), cell("C_HJX_BLE_SET_VOL", 2400), cell("APP→设备", 1800), cell("设置音量", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0xA4", 1200), cell("C_HJX_BLE_SET_MODE", 2400), cell("APP→设备", 1800), cell("切换工作模式", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0xAC", 1200), cell("C_HJX_BLE_RESET", 2400), cell("APP→设备", 1800), cell("复位 HAP150", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0xF1", 1200), cell("C_EEP_DATA_TRANCE", 2400), cell("APP→设备", 1800), cell("开启强制烧录全片", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0xF2", 1200), cell("C_EEP_DATA_UPDATE", 2400), cell("APP→设备", 1800), cell("分次烧录数据", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0xF3", 1200), cell("C_EEP_DATA_CHECK", 2400), cell("APP→设备", 1800), cell("校验并写入 Flash", 3960)
          ]}),
          new TableRow({ children: [
            hexCell("0xF6", 1200), cell("C_EEP_DATA_READ", 2400), cell("APP→设备", 1800), cell("读取指定地址数据", 3960)
          ]}),
          new TableRow({ children: [
