          ]}),
        ]
      }),

      // ===== CRC算法 =====
      new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun("6. CRC-16 校验算法")] }),

      new Paragraph({ spacing: { after: 80 },
        children: [new TextRun({ text: "所有数据包末尾附加 2 字节 CRC-16 校验码（低字节在前，高字节在后）。", size: 20, font: "Arial" })] }),
      new Paragraph({ spacing: { after: 80 },
        children: [new TextRun({ text: "多项式：0xA001（标准 CRC-16）", size: 20, font: "Arial" })] }),
      new Paragraph({ spacing: { after: 120 },
        children: [new TextRun({ text: "计算范围：从 flag 字节到数据最后一个字节（不包含 CRC 本身）", size: 20, font: "Arial" })] }),

      new Paragraph({ spacing: { after: 80 },
        children: [new TextRun({ text: "C 语言实现（来源：s_HJXPCDataDeal() / GetCrC()）：", size: 20, font: "Arial", bold: true })] }),
      new Paragraph({ spacing: { after: 120 },
        children: [new TextRun({ text: "void GetCrC(u8 *buf, u16 len, u8 *crc) { u16 crc16 = 0xFFFF; for (u16 i = 0; i < len; i++) { crc16 ^= buf[i]; for (u8 j = 0; j < 8; j++) { if (crc16 & 0x01) { crc16 >>= 1; crc16 ^= 0xA001; } else { crc16 >>= 1; } } } crc[0] = crc16 % 0x100; crc[1] = crc16 / 0x100; }", size: 17, font: "Consolas" })] }),

      // ===== 版本历史 =====
      new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun("7. 版本历史")] }),
      new Table({
        columnWidths: [1800, 7560],
        rows: [
          new TableRow({ children: [hcell("版本", 1800), hcell("说明", 7560)] }),
          new TableRow({ children: [cell("V1.0", 1800), cell("2026-04-20 初始版本，包含 PC 协议 4 条 + APP 协议 10 条", 7560)] }),
        ]
      }),
    ]
  }]
});

