const cellBorders = { top: tableBorder, bottom: tableBorder, left: tableBorder, right: tableBorder };
const headerShading = { fill: "D0E8F0", type: ShadingType.CLEAR };

// Helper: create table cell
function cell(text, width, options = {}) {
  return new TableCell({
    borders: cellBorders,
    width: { size: width, type: WidthType.DXA },
    shading: options.shading || { fill: "FFFFFF", type: ShadingType.CLEAR },
    verticalAlign: VerticalAlign.CENTER,
    children: [new Paragraph({
      alignment: options.align || AlignmentType.LEFT,
      spacing: { before: 60, after: 60 },
      children: [new TextRun({
        text: text,
        bold: options.bold || false,
        size: options.size || 20,
        font: "Arial",
        color: options.color || "000000"
      })]
    })]
  });
}

// Helper: hex cell
function hexCell(text, width) {
  return cell(text, width, { align: AlignmentType.CENTER });
}

// Helper: header cell
function hcell(text, width) {
  return cell(text, width, { bold: true, shading: headerShading, align: AlignmentType.CENTER });
}

